1314→/// Start MCP stdio server. Blocks until client disconnects.
1315→///
1316→/// Lifecycle: serve → waiting. Officium created by explicit jjx_open call.
1317→pub async fn jjrm_serve_stdio() -> Result<(), Box<dyn std::error::Error>> {
1318→    use rmcp::ServiceExt;
1319→
1320→    let server = jjrm_McpServer::jjrm_new();
1321→    let service = server
1322→        .serve(rmcp::transport::stdio())
1323→        .await
1324→        .map_err(|e| format!("MCP serve error: {}", e))?;
1325→
1326→    service.waiting().await?;
1327→    Ok(())
1328→}
