130→// Dispatch lifecycle — jjsodp_command_lifecycle (Operation Taxonomy in JJS0)
131→// ============================================================================
132→
133→/// Shared dispatch body: lock → load → call handler → persist → return output.
134→///
135→/// Per jjdk_sole_operator, every operation locks and persists unconditionally.
136→/// The handler returns output text on success — it has no knowledge of locks,
137→/// persistence, or commit messages.
138→fn zjjrm_dispatch_inner(
139→    cmd: &str,
140→    firemark: &crate::jjrf_favor::jjrf_Firemark,
141→    handler: impl FnOnce(&mut crate::jjrg_gallops::jjrg_Gallops) -> Result<String, String>,
142→) -> Result<CallToolResult, McpError> {
143→    use vvc::vvco_Output;
144→
145→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
146→        Ok(l) => l,
147→        Err(e) => {
148→            return Ok(CallToolResult::error(vec![Content::text(
149→                format!("jjx {}: error: {}", cmd, e),
150→            )]));
151→        }
152→    };
153→
154→    let gallops_path = gallops_pathbuf();
155→    let mut gallops = match crate::jjrg_gallops::jjrg_Gallops::jjrg_load(&gallops_path) {
156→        Ok(g) => g,
157→        Err(e) => {
158→            return Ok(CallToolResult::error(vec![Content::text(
159→                format!("jjx {}: error loading Gallops: {}", cmd, e),
160→            )]));
161→        }
162→    };
163→
164→    let output = match handler(&mut gallops) {
165→        Ok(o) => o,
166→        Err(e) => {
167→            return Ok(CallToolResult::error(vec![Content::text(
168→                format!("jjx {}: error: {}", cmd, e),
169→            )]));
170→        }
171→    };
172→
173→    let mut persist_output = vvco_Output::buffer();
174→    match crate::jjri_io::jjri_persist(
175→        &lock,
176→        &gallops,
177→        &gallops_path,
178→        firemark,
179→        format!("jjx: {}", cmd),
180→        50000,
181→        &mut persist_output,
182→    ) {
183→        Ok(_hash) => {}
184→        Err(e) => {
185→            return Ok(CallToolResult::error(vec![Content::text(
186→                format!("jjx {}: error: {}", cmd, e),
187→            )]));
188→        }
189→    }
190→
191→    Ok(CallToolResult::success(vec![Content::text(output)]))
192→}
