195→/// Dispatch a pace-affiliated command. Coronet supplied from params; parent firemark derived.
196→fn jjrm_dispatch_pace(
197→    cmd: &str,
198→    coronet_str: &str,
199→    handler: impl FnOnce(&mut crate::jjrg_gallops::jjrg_Gallops) -> Result<String, String>,
200→) -> Result<CallToolResult, McpError> {
201→    let coronet = match crate::jjrf_favor::jjrf_Coronet::jjrf_parse(coronet_str) {
202→        Ok(c) => c,
203→        Err(e) => {
204→            return Ok(CallToolResult::error(vec![Content::text(
205→                format!("jjx {}: error: {}", cmd, e),
206→            )]));
207→        }
208→    };
209→    let firemark = coronet.jjrf_parent_firemark();
210→    zjjrm_dispatch_inner(cmd, &firemark, handler)
211→}
