450→/// Reap stale officium directories by heartbeat mtime.
451→fn zjjrm_exsanguinate(officia: &Path) {
452→    let entries = match std::fs::read_dir(officia) {
453→        Ok(e) => e,
454→        Err(_) => return,
455→    };
456→    let now = std::time::SystemTime::now();
457→    for entry in entries.flatten() {
458→        let path = entry.path();
459→        if !path.is_dir() { continue; }
460→        let heartbeat = path.join(HEARTBEAT_FILE);
461→        if !heartbeat.exists() {
462→            // No heartbeat file — legacy or corrupt. Log warning, skip.
463→            eprintln!("jjx exsanguinate: no heartbeat in {:?}, skipping", path.file_name());
464→            continue;
465→        }
466→        let mtime = match heartbeat.metadata().and_then(|m| m.modified()) {
467→            Ok(t) => t,
468→            Err(_) => continue,
469→        };
470→        let age = match now.duration_since(mtime) {
471→            Ok(d) => d,
472→            Err(_) => continue,
473→        };
474→        if age.as_secs() > EXSANGUINATION_THRESHOLD_SECS {
475→            if let Err(e) = std::fs::remove_dir_all(&path) {
476→                eprintln!("jjx exsanguinate: failed to remove {:?}: {}", path.file_name(), e);
477→            }
478→        }
479→    }
480→}
