482→/// Generate officium ID: YYMMDD-NNNN (autonumber from directory listing).
483→fn zjjrm_generate_officium_id(officia: &Path, today: &str) -> String {
484→    let prefix = format!("{}-", today);
485→    let mut max_num: u32 = 999;
486→    if let Ok(entries) = std::fs::read_dir(officia) {
487→        for entry in entries.flatten() {
488→            let name = entry.file_name();
489→            let name = name.to_string_lossy();
490→            if let Some(suffix) = name.strip_prefix(&prefix) {
491→                if let Ok(num) = suffix.parse::<u32>() {
492→                    if num > max_num { max_num = num; }
493→                }
494→            }
495→        }
496→    }
497→    format!("{}{:04}", prefix, max_num + 1)
498→}
