508→/// Validate officium directory exists and touch heartbeat.
509→fn zjjrm_validate_officium(officium: &str) -> Result<(), String> {
510→    let bare_id = officium.trim_start_matches(OFFICIUM_SUN_PREFIX);
511→    let exchange = PathBuf::from(OFFICIA_DIR).join(bare_id);
512→    if !exchange.is_dir() {
513→        return Err(format!(
514→            "Officium directory not found: {}. Call jjx_open to create a new officium.",
515→            bare_id
516→        ));
517→    }
518→    // Touch heartbeat
519→    std::fs::write(exchange.join(HEARTBEAT_FILE), b"").ok();
520→    Ok(())
521→}
