535→/// Handle jjx_open: create a new officium.
536→async fn zjjrm_handle_open() -> Result<CallToolResult, McpError> {
537→    let cn = JJRM_CMD_NAME_OPEN;
538→    let mut output = vvc::vvco_Output::buffer();
539→
540→    // Disk space guard — block before any state changes
