635→/// Handle jjx_chapter: list active officia with status.
636→fn zjjrm_handle_chapter(caller_officium: &str) -> Result<CallToolResult, McpError> {
637→    let cn = JJRM_CMD_NAME_CHAPTER;
638→    let bare_caller_id = caller_officium.trim_start_matches(OFFICIUM_SUN_PREFIX);
639→    let officia = PathBuf::from(OFFICIA_DIR);
640→
641→    let entries = match std::fs::read_dir(&officia) {
642→        Ok(e) => e,
643→        Err(e) => {
644→            return Ok(CallToolResult::error(vec![Content::text(
645→                format!("{}: cannot read officia dir: {}", cn, e),
646→            )]));
647→        }
648→    };
649→
650→    let now = std::time::SystemTime::now();
651→
652→    struct RowInfo {
653→        identity: String,
654→        created_str: String,
655→        heartbeat_str: String,
656→        age_str: String,
657→        status: String,
658→        caller_marker: &'static str,
659→    }
660→
661→    let mut rows: Vec<RowInfo> = Vec::new();
662→
663→    for entry in entries.flatten() {
664→        let path = entry.path();
665→        if !path.is_dir() { continue; }
666→        let dir_name = match path.file_name() {
667→            Some(n) => n.to_string_lossy().to_string(),
668→            None => continue,
669→        };
670→        // Skip hidden files/dirs (e.g. .probe_date is a file, not a dir, but guard anyway)
671→        if dir_name.starts_with('.') { continue; }
672→
673→        let identity = format!("{}{}", OFFICIUM_SUN_PREFIX, dir_name);
674→        let caller_marker = if dir_name == bare_caller_id { " \u{2190} you" } else { "" };
675→
676→        // Created: try created(), fall back to modified()
677→        let created_str = match path.metadata() {
678→            Ok(meta) => {
679→                let time = meta.created().or_else(|_| meta.modified()).ok();
680→                match time {
681→                    Some(t) => {
682→                        let dt: chrono::DateTime<chrono::Local> = t.into();
683→                        dt.format("%y%m%d-%H%M").to_string()
684→                    }
685→                    None => "?".to_string(),
686→                }
687→            }
688→            Err(_) => "?".to_string(),
689→        };
690→
691→        let heartbeat_path = path.join(HEARTBEAT_FILE);
692→        let (heartbeat_str, age_str, status) = match heartbeat_path.metadata().and_then(|m| m.modified()) {
693→            Ok(hb_mtime) => {
694→                let dt: chrono::DateTime<chrono::Local> = hb_mtime.into();
695→                let hb_str = dt.format("%y%m%d-%H%M").to_string();
696→                let age = now.duration_since(hb_mtime).unwrap_or_default();
697→                let age_secs = age.as_secs();
698→                let age_str = if age_secs < 60 {
699→                    format!("{}s", age_secs)
700→                } else if age_secs < 3600 {
701→                    format!("{}m", age_secs / 60)
702→                } else {
703→                    format!("{}h{}m", age_secs / 3600, (age_secs % 3600) / 60)
704→                };
705→                let status = if age_secs > EXSANGUINATION_THRESHOLD_SECS {
706→                    "stale".to_string()
707→                } else {
708→                    "active".to_string()
709→                };
710→                (hb_str, age_str, status)
711→            }
712→            Err(_) => ("?".to_string(), "?".to_string(), "unknown".to_string()),
713→        };
714→
715→        rows.push(RowInfo {
716→            identity,
717→            created_str,
718→            heartbeat_str,
719→            age_str,
720→            status,
721→            caller_marker,
722→        });
723→    }
724→
725→    if rows.is_empty() {
726→        return Ok(CallToolResult::success(vec![Content::text("No officia found.".to_string())]));
727→    }
728→
729→    // Sort by identity for stable output
730→    rows.sort_by(|a, b| a.identity.cmp(&b.identity));
731→
732→    // Build aligned table
733→    let header = format!("{:<20}  {:<12}  {:<12}  {:>7}  {:<8}",
734→        "Officium", "Created", "Heartbeat", "Age", "Status");
735→    let separator = "-".repeat(header.len() + 16);
736→    let mut lines = vec![header, separator];
737→    for row in &rows {
738→        lines.push(format!("{:<20}  {:<12}  {:<12}  {:>7}  {:<8}{}",
739→            row.identity,
740→            row.created_str,
741→            row.heartbeat_str,
742→            row.age_str,
743→            row.status,
744→            row.caller_marker,
745→        ));
746→    }
747→
748→    Ok(CallToolResult::success(vec![Content::text(lines.join("\n"))]))
749→}
